const amqp = require('amqplib');

const RABBITMQ_URL = process.env.RABBITMQ_URL || 'amqp://localhost';
const QUEUE_NAME = process.env.QUEUE_NAME || 'payment_events';
const PREFETCH = Number(process.env.PREFETCH || 10);

async function processPayment(event) {
  const {
    paymentId,
    userId,
    amount,
    currency,
    source,
    destination,
    action,
    metadata
  } = event;

  console.log('Processing payment event:', {
    paymentId,
    userId,
    amount,
    currency,
    source,
    destination,
    action,
    metadata
  });

  switch (action) {
    case 'charge':
      console.log(`Charging ${amount} ${currency} from source ${source} for user ${userId}`);
      break;
    case 'refund':
      console.log(`Refunding ${amount} ${currency} to destination ${destination} for user ${userId}`);
      break;
    case 'transfer':
      console.log(`Transferring ${amount} ${currency} from ${source} to ${destination}`);
      break;
    default:
      console.log(`Unknown action "${action}" for payment ${paymentId}`);
      break;
  }

  await new Promise(resolve => setTimeout(resolve, 250));

  console.log(`Payment event processed: ${paymentId}`);
}

async function startConsumer() {
  const connection = await amqp.connect(RABBITMQ_URL);
  const channel = await connection.createChannel();

  await channel.assertQueue(QUEUE_NAME, { durable: true });
  await channel.prefetch(PREFETCH);

  console.log(`Waiting for messages on queue "${QUEUE_NAME}"`);

  channel.consume(
    QUEUE_NAME,
    async msg => {
      if (!msg) return;

      try {
        const content = msg.content.toString('utf8');
        const event = JSON.parse(content);

        await processPayment(event);
        channel.ack(msg);
      } catch (error) {
        console.error('Failed to process payment event:', error);
        channel.nack(msg, false, false);
      }
    },
    { noAck: false }
  );

  const shutdown = async signal => {
    console.log(`Received ${signal}, shutting down...`);
    try {
      await channel.close();
      await connection.close();
    } catch (err) {
      console.error('Shutdown error:', err);
    } finally {
      process.exit(0);
    }
  };

  process.on('SIGINT', () => shutdown('SIGINT'));
  process.on('SIGTERM', () => shutdown('SIGTERM'));
}

startConsumer().catch(err => {
  console.error('Consumer startup failed:', err);
  process.exit(1);
});